function status(node,msg,ok=false){if(!node)return;node.textContent=msg;node.style.color=msg?(ok?"var(--success)":"var(--danger)"):"var(--text-muted)";}
function setError(id,msg){const n=document.querySelector(`[data-error-for="${id}"]`);if(n)n.textContent=msg;}
function clearErrors(form){if(form)form.querySelectorAll(".error").forEach(n=>n.textContent="");}
function loadUsers(){return JSON.parse(localStorage.getItem(STORAGE_KEYS.users)||"[]");}
function saveUsers(users){localStorage.setItem(STORAGE_KEYS.users,JSON.stringify(users));}
function validateUserId(userId,errorId){
if(!userId||userId.trim().length<8){setError(errorId,"User ID must be at least 8 characters.");return false;}
return true;
}
function validatePassword(password,errorId){
if(!passwordPattern.test(String(password||""))){setError(errorId,"Password must be 8+ characters with uppercase, lowercase, and a special character.");return false;}
return true;
}
