async function api(path,options={}){const headers=new Headers(options.headers||{});if(!(options.body instanceof FormData))headers.set("Content-Type","application/json");if(state.user)headers.set("x-user-id",state.user);const r=await fetch(`${API_BASE}${path}`,{...options,headers});const p=await r.json().catch(()=>({}));if(!r.ok)throw new Error(p.error||"Request failed.");return p;}
function formatCurrency(a){return new Intl.NumberFormat("en-IN",{style:"currency",currency:"INR",maximumFractionDigits:2}).format(a);}
function formatDateTime(v){const d=new Date(v);return Number.isNaN(d.getTime())?"Invalid date":d.toLocaleString("en-IN",{year:"numeric",month:"short",day:"numeric",hour:"2-digit",minute:"2-digit"});}
function formatBytes(size){if(!size)return"0 B";const u=["B","KB","MB","GB"],i=Math.min(Math.floor(Math.log(size)/Math.log(1024)),u.length-1);return`${(size/(1024**i)).toFixed(i?1:0)} ${u[i]}`;}
function normalizeTag(t){return t.trim().toLowerCase().replace(/\s+/g,"-");}
function dateValue(day,month,year,hour="00",minute="00"){if(!day||!month||!year)return"";const d=new Date(`${year}-${month}-${day}T${hour}:${minute}:00`);return Number.isNaN(d.getTime())?"":d.toISOString();}
function attachmentUrl(a){return a.path?`${API_BASE}/${a.path.split("/").map(encodeURIComponent).join("/")}`:"#";}
function tokens(text){return String(text||"").toLowerCase().split(/\s+/).map(t=>t.trim()).filter(Boolean);}
function fuzzyScore(query,target){const qs=tokens(query),ts=tokens(target);if(!qs.length||!ts.length)return 0;let score=0;for(const q of qs){if(ts.some(t=>t.includes(q)))score+=3;else if(ts.some(t=>levenshtein(q,t)<=2))score+=1;}return score;}
function levenshtein(a,b){const m=a.length,n=b.length,dp=Array.from({length:m+1},()=>Array(n+1).fill(0));for(let i=0;i<=m;i+=1)dp[i][0]=i;for(let j=0;j<=n;j+=1)dp[0][j]=j;for(let i=1;i<=m;i+=1){for(let j=1;j<=n;j+=1){const c=a[i-1]===b[j-1]?0:1;dp[i][j]=Math.min(dp[i-1][j]+1,dp[i][j-1]+1,dp[i-1][j-1]+c);}}return dp[m][n];}

function populateSelect(select,from,to,pad=2){if(!select||select.options.length>1)return;for(let i=from;i<=to;i+=1){const o=document.createElement("option");o.value=String(i).padStart(pad,"0");o.textContent=String(i).padStart(pad,"0");select.append(o);}}
function populateYears(select,start,end,desc=true){if(!select||select.options.length>1)return;const arr=[];for(let y=start;y<=end;y+=1)arr.push(y);if(desc)arr.reverse();arr.forEach(y=>{const o=document.createElement("option");o.value=String(y);o.textContent=String(y);select.append(o);});}
