function escapeHtml(value){return String(value??"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;");}
function chartColor(index){const colors=["#7cc7ff","#71e1c1","#ffb370","#ff8ea1","#d4b3ff","#89f0ff","#ffd36b","#9db8ff"];return colors[index%colors.length];}
function downloadVisualization(){const payload=state.vizDownloadData;if(!payload){status(els.txStatus,"No chart available to download.");return;}const width=1200,height=760,pad=56;const canvas=document.createElement("canvas");canvas.width=width;canvas.height=height;const ctx=canvas.getContext("2d");const theme=getComputedStyle(document.body);const bg=theme.getPropertyValue("--panel-strong").trim()||"#101727";const text=theme.getPropertyValue("--text").trim()||"#ebf2ff";const muted=theme.getPropertyValue("--text-muted").trim()||"#95a3bf";const border=theme.getPropertyValue("--border").trim()||"rgba(150, 180, 255, 0.16)";ctx.fillStyle=bg;ctx.fillRect(0,0,width,height);ctx.strokeStyle=border;ctx.lineWidth=2;ctx.strokeRect(24,24,width-48,height-48);ctx.fillStyle=text;ctx.font='700 30px "Plus Jakarta Sans", sans-serif';ctx.fillText(payload.title||"Chart",pad,56);ctx.fillStyle=muted;ctx.font='500 18px "Plus Jakarta Sans", sans-serif';ctx.fillText(payload.context||"",pad,88);const fmt=value=>payload.yField==="count"?String(Math.round(value)):formatCurrency(value);if(payload.type==="pie"){const radius=190;const cx=350,cy=390;const total=payload.data.reduce((sum,item)=>sum+item.value,0)||1;let cursor=-Math.PI/2;payload.data.forEach((item,index)=>{const angle=(item.value/total)*Math.PI*2;ctx.beginPath();ctx.moveTo(cx,cy);ctx.arc(cx,cy,radius,cursor,cursor+angle);ctx.closePath();ctx.fillStyle=chartColor(index);ctx.fill();cursor+=angle;});ctx.fillStyle=bg;ctx.beginPath();ctx.arc(cx,cy,radius*0.5,0,Math.PI*2);ctx.fill();payload.data.forEach((item,index)=>{const y=170+index*58;ctx.fillStyle=chartColor(index);ctx.beginPath();ctx.arc(690,y,8,0,Math.PI*2);ctx.fill();ctx.fillStyle=text;ctx.font='600 20px "Plus Jakarta Sans", sans-serif';ctx.fillText(item.label,710,y+6);ctx.fillStyle=muted;ctx.font='500 18px "Plus Jakarta Sans", sans-serif';ctx.fillText(fmt(item.value),930,y+6);});}else if(payload.type==="histogram"){const chartX=90,chartY=150,chartW=1020,chartH=500;const max=Math.max(...payload.data.map(item=>item.value),1);ctx.strokeStyle=border;ctx.lineWidth=1;for(let i=0;i<=4;i+=1){const y=chartY+chartH-(chartH/4)*i;ctx.beginPath();ctx.moveTo(chartX,y);ctx.lineTo(chartX+chartW,y);ctx.stroke();ctx.fillStyle=muted;ctx.font='500 16px "Plus Jakarta Sans", sans-serif';ctx.fillText(String(Math.round((max/4)*i)),chartX-48,y+6);}const barW=Math.min(100,chartW/Math.max(payload.data.length,1)-22);payload.data.forEach((item,index)=>{const x=chartX+index*(barW+22)+12;const h=Math.max((item.value/max)*chartH,12);const y=chartY+chartH-h;ctx.fillStyle=chartColor(index);ctx.fillRect(x,y,barW,h);ctx.fillStyle=text;ctx.font='600 16px "Plus Jakarta Sans", sans-serif';ctx.fillText(String(item.value),x,y-10);ctx.fillStyle=muted;ctx.font='500 16px "Plus Jakarta Sans", sans-serif';ctx.save();ctx.translate(x+barW*0.5,chartY+chartH+28);ctx.rotate(-0.35);ctx.fillText(item.label,-Math.min(42,item.label.length*4),0);ctx.restore();});}else if(payload.type==="scatter"){const chartX=110,chartY=140,chartW=980,chartH=500;const maxX=Math.max(...payload.data.map(point=>point.x),1);const maxY=Math.max(...payload.data.map(point=>point.y),1);ctx.strokeStyle=border;ctx.lineWidth=1;for(let i=0;i<=4;i+=1){const y=chartY+chartH-(chartH/4)*i;ctx.beginPath();ctx.moveTo(chartX,y);ctx.lineTo(chartX+chartW,y);ctx.stroke();ctx.fillStyle=muted;ctx.font='500 16px "Plus Jakarta Sans", sans-serif';ctx.fillText(String(Math.round((maxY/4)*i)),chartX-52,y+6);}for(let i=0;i<=4;i+=1){const x=chartX+(chartW/4)*i;ctx.beginPath();ctx.moveTo(x,chartY);ctx.lineTo(x,chartY+chartH);ctx.stroke();ctx.fillStyle=muted;ctx.font='500 16px "Plus Jakarta Sans", sans-serif';ctx.fillText(String(Math.round((maxX/4)*i)),x-10,chartY+chartH+28);}payload.data.forEach(point=>{const px=chartX+(point.x/maxX)*chartW;const py=chartY+chartH-(point.y/maxY)*chartH;ctx.beginPath();ctx.fillStyle=chartColor(Math.max(TYPES.indexOf(point.color),0));ctx.arc(px,py,8,0,Math.PI*2);ctx.fill();});ctx.fillStyle=text;ctx.font='600 18px "Plus Jakarta Sans", sans-serif';ctx.fillText(`X: ${payload.xField}`,chartX,chartY+chartH+56);ctx.fillText(`Y: ${payload.yField}`,chartX+180,chartY+chartH+56);}const link=document.createElement("a");const chartName=(payload.title||"chart").trim().toLowerCase().replace(/\s+/g,"-");link.href=canvas.toDataURL("image/png");link.download=`${chartName}.png`;document.body.append(link);link.click();link.remove();status(els.txStatus,"Chart downloaded.",true);}
function transactionsForCurrentScope(){return state.note?state.transactions.filter(tx=>tx.note_id===state.note):state.transactions;}
function visualizationList(){let list=transactionsForCurrentScope();const start=els.vizStartDate?.value;const end=els.vizEndDate?.value;if(start)list=list.filter(tx=>String(tx.occurredAt||"").slice(0,10)>=start);if(end)list=list.filter(tx=>String(tx.occurredAt||"").slice(0,10)<=end);return list;}
function transactionMetric(tx,field){if(field==="count")return 1;if(field==="amount")return Number(tx.amount||0);if(field==="expected-return")return Number(tx.calculated?.expectedReturn||0);if(field==="final-amount")return Number(tx.calculated?.finalAmount||0);if(field==="tag-count")return (tx.tags||[]).length;return Number(tx.amount||0);}
function transactionDimension(tx,field){const d=new Date(tx.occurredAt);if(field==="type")return tx.type;if(field==="month")return Number.isNaN(d.getTime())?"Unknown":d.toLocaleString("en-IN",{month:"short",year:"numeric"});if(field==="day")return Number.isNaN(d.getTime())?"Unknown":d.toLocaleDateString("en-IN",{day:"2-digit",month:"short"});if(field==="note")return tx.note?.title||"No note";if(field==="creator")return tx.creator?.collaborator_tag||tx.user_id||"Unknown";if(field==="tag-count")return `${(tx.tags||[]).length} tags`;if(field==="amount")return Number(tx.amount||0);return tx.type;}
function numericDimension(tx,field){const d=new Date(tx.occurredAt);if(field==="amount")return Number(tx.amount||0);if(field==="tag-count")return (tx.tags||[]).length;if(field==="month")return Number.isNaN(d.getTime())?0:d.getMonth()+1;if(field==="day")return Number.isNaN(d.getTime())?0:d.getDate();return Number(tx.amount||0);}
function aggregateVisualizationData(list,xField,yField){const map=new Map();list.forEach(tx=>{const key=String(transactionDimension(tx,xField));map.set(key,(map.get(key)||0)+transactionMetric(tx,yField));});return [...map.entries()].map(([label,value])=>({label,value})).sort((a,b)=>b.value-a.value);}
function histogramData(list,yField){const values=list.map(tx=>transactionMetric(tx,yField)).filter(v=>Number.isFinite(v));if(!values.length)return[];const min=Math.min(...values),max=Math.max(...values);const bins=Math.min(Math.max(Math.ceil(Math.sqrt(values.length)),4),8);const span=max-min||1;const size=span/bins;const result=Array.from({length:bins},(_,index)=>({label:`${(min+size*index).toFixed(0)}-${(min+size*(index+1)).toFixed(0)}`,value:0}));values.forEach(value=>{const raw=Math.min(Math.floor((value-min)/size),bins-1);result[raw].value+=1;});return result;}
function scatterData(list,xField,yField){return list.map(tx=>({label:tx.type,x:numericDimension(tx,xField),y:transactionMetric(tx,yField),color:tx.type})).filter(point=>Number.isFinite(point.x)&&Number.isFinite(point.y));}
function threeDData(list,xField,yField,zField){const groups=new Map();list.forEach(tx=>{const zKey=String(transactionDimension(tx,zField));const xKey=String(transactionDimension(tx,xField));if(!groups.has(zKey))groups.set(zKey,new Map());const zMap=groups.get(zKey);zMap.set(xKey,(zMap.get(xKey)||0)+transactionMetric(tx,yField));});return [...groups.entries()].map(([zLabel,xMap])=>({zLabel,items:[...xMap.entries()].map(([label,value])=>({label,value})).sort((a,b)=>b.value-a.value)}));}
function visualizationFieldLabel(field){return{type:"Transaction Type",month:"Month",day:"Day",note:"Note",creator:"Created By","tag-count":"Tag Count",amount:"Amount",count:"Count","expected-return":"Expected Return","final-amount":"Final Amount"}[field]||field;}
function clampLabel(label,max=18){const value=String(label??"");return value.length>max?`${value.slice(0,max-1)}…`:value;}
function hexToRgba(hex,alpha=1){const value=String(hex||"#7cc7ff").replace("#","");const safe=value.length===3?value.split("").map(ch=>ch+ch).join(""):value;const int=parseInt(safe,16);const r=(int>>16)&255,g=(int>>8)&255,b=int&255;return `rgba(${r}, ${g}, ${b}, ${alpha})`;}
function pieMarkup(data){const total=data.reduce((sum,item)=>sum+item.value,0)||1;let cursor=0;const stops=data.map((item,index)=>{const start=(cursor/total)*360;cursor+=item.value;const end=(cursor/total)*360;return `${chartColor(index)} ${start}deg ${end}deg`;}).join(", ");return `<div class="viz-pie" style="background:conic-gradient(${stops||`${chartColor(0)} 0deg 360deg`})"></div>`;}
function legendMarkup(data,formatter=value=>value){return `<div class="viz-legend">${data.map((item,index)=>`<div class="viz-legend-item"><span class="viz-swatch" style="background:${chartColor(index)}"></span><span>${escapeHtml(item.label)} • ${escapeHtml(formatter(item.value))}</span></div>`).join("")}</div>`;}
function histogramMarkup(data){const max=Math.max(...data.map(item=>item.value),1);return `<div class="viz-histogram">${data.map(item=>`<div class="viz-hist-bar"><span class="viz-axis-value">${item.value}</span><div class="viz-hist-bar-fill" style="height:${Math.max((item.value/max)*220,18)}px"></div><span class="viz-axis-label">${escapeHtml(item.label)}</span></div>`).join("")}</div>`;}
function threeDMarkup(data,formatter=value=>value){const max=Math.max(...data.map(item=>item.value),1);return `<div class="viz-3d-grid">${data.map(item=>`<div class="viz-3d-bar"><span class="viz-axis-value">${escapeHtml(formatter(item.value))}</span><div class="viz-3d-box" style="height:${Math.max((item.value/max)*220,24)}px"></div><span class="viz-axis-label">${escapeHtml(item.label)}</span></div>`).join("")}</div>`;}
function threeDSceneMarkup(groups,xField,yField,zField,formatter=value=>value){
if(!groups.length)return'<div class="viz-empty">Choose a valid Z axis to build the 3D graph.</div>';
const xTotals=new Map();
groups.forEach(group=>group.items.forEach(item=>xTotals.set(item.label,(xTotals.get(item.label)||0)+item.value)));
let xLabels=[...xTotals.entries()].sort((a,b)=>b[1]-a[1]).slice(0,6).map(([label])=>label);
let zLabels=groups.slice(0,6).map(group=>group.zLabel);
if(!xLabels.length||!zLabels.length)return'<div class="viz-empty">Not enough points for a 3D graph.</div>';
if(xLabels.length===1)xLabels=[xLabels[0],`${xLabels[0]} copy`];
if(zLabels.length===1)zLabels=[zLabels[0],`${zLabels[0]} copy`];
const valueLookup=new Map(groups.map(group=>[group.zLabel,new Map(group.items.map(item=>[item.label,item.value]))]));
const baseMatrix=zLabels.map(zLabel=>xLabels.map(xLabel=>Number(valueLookup.get(zLabel)?.get(xLabel)||0)));
const maxValue=Math.max(...baseMatrix.flat(),1);
const minValue=Math.min(...baseMatrix.flat(),0);
const xSpan=Math.max(xLabels.length-1,1);
const zSpan=Math.max(zLabels.length-1,1);
const width=1180,height=780;
const origin={x:360,y:610};
const xVector={x:Math.min(150,620/Math.max(xSpan+1,2)),y:Math.min(24,92/Math.max(xSpan+1,2))};
const zVector={x:Math.min(102,290/Math.max(zSpan+1,2)),y:-Math.min(54,138/Math.max(zSpan+1,2))};
const heightScale=250/maxValue;
const project=(x,y,z)=>({x:origin.x+x*xVector.x+z*zVector.x,y:origin.y+x*xVector.y+z*zVector.y-y*heightScale});
const lerp=(a,b,t)=>a+(b-a)*t;
const bilinear=(q11,q21,q12,q22,tx,tz)=>lerp(lerp(q11,q21,tx),lerp(q12,q22,tx),tz);
const gradientStops=["#162032","#244468","#2b6ea0","#2896bf","#2fc8c4","#78e19d","#f5d55f"];
const colorAt=t=>{const clamped=Math.max(0,Math.min(0.999,t));const scaled=clamped*(gradientStops.length-1);const left=Math.floor(scaled);const right=Math.min(left+1,gradientStops.length-1);const mix=scaled-left;const parse=hex=>hex.match(/[a-f\d]{2}/gi).map(part=>parseInt(part,16));const [r1,g1,b1]=parse(gradientStops[left].replace("#",""));const [r2,g2,b2]=parse(gradientStops[right].replace("#",""));return`rgb(${Math.round(lerp(r1,r2,mix))}, ${Math.round(lerp(g1,g2,mix))}, ${Math.round(lerp(b1,b2,mix))})`;};
const surfacePolygons=[];
const surfaceLines=[];
const xSegments=Math.max((xLabels.length-1)*8,8);
const zSegments=Math.max((zLabels.length-1)*8,8);
for(let zi=zSegments-1;zi>=0;zi-=1){
for(let xi=xSegments-1;xi>=0;xi-=1){
const x0=xi/xSegments*xSpan,x1=(xi+1)/xSegments*xSpan,z0=zi/zSegments*zSpan,z1=(zi+1)/zSegments*zSpan;
const xCell=Math.min(Math.floor(x0),xLabels.length-2),zCell=Math.min(Math.floor(z0),zLabels.length-2);
const tx0=x0-xCell,tx1=x1-xCell,tz0=z0-zCell,tz1=z1-zCell;
const q11=baseMatrix[zCell][xCell],q21=baseMatrix[zCell][xCell+1],q12=baseMatrix[zCell+1][xCell],q22=baseMatrix[zCell+1][xCell+1];
const y00=bilinear(q11,q21,q12,q22,tx0,tz0),y10=bilinear(q11,q21,q12,q22,tx1,tz0),y11=bilinear(q11,q21,q12,q22,tx1,tz1),y01=bilinear(q11,q21,q12,q22,tx0,tz1);
const p00=project(x0,y00,z0),p10=project(x1,y10,z0),p11=project(x1,y11,z1),p01=project(x0,y01,z1);
const avg=(y00+y10+y11+y01)/4;
const normalized=(avg-minValue)/Math.max(maxValue-minValue,1);
surfacePolygons.push(`<polygon points="${p00.x},${p00.y} ${p10.x},${p10.y} ${p11.x},${p11.y} ${p01.x},${p01.y}" fill="${colorAt(normalized)}" class="viz-3d-surface-cell"></polygon>`);
surfaceLines.push(`<polyline points="${p00.x},${p00.y} ${p10.x},${p10.y} ${p11.x},${p11.y} ${p01.x},${p01.y} ${p00.x},${p00.y}" class="viz-3d-surface-wire"></polyline>`);
}}
const floorPlane=`<polygon points="${project(0,0,0).x},${project(0,0,0).y} ${project(xSpan,0,0).x},${project(xSpan,0,0).y} ${project(xSpan,0,zSpan).x},${project(xSpan,0,zSpan).y} ${project(0,0,zSpan).x},${project(0,0,zSpan).y}" class="viz-3d-floor-plane"></polygon>`;
const backdrop=`<rect x="92" y="74" width="${width-184}" height="${height-164}" rx="30" class="viz-3d-backdrop"></rect>`;
const axes=[];
const labels=[];
const grid=[];
const yTicks=5;
for(let i=0;i<=yTicks;i+=1){
const value=maxValue/yTicks*i;
const left=project(0,value,0),right=project(xSpan,value,0),back=project(0,value,zSpan);
grid.push(`<line x1="${left.x}" y1="${left.y}" x2="${right.x}" y2="${right.y}" class="viz-3d-grid-line"></line>`);
grid.push(`<line x1="${left.x}" y1="${left.y}" x2="${back.x}" y2="${back.y}" class="viz-3d-grid-line viz-3d-grid-line-depth"></line>`);
labels.push(`<text x="${left.x-96}" y="${left.y+5}" class="viz-3d-tick">${escapeHtml(formatter(value))}</text>`);
}
for(let i=0;i<xLabels.length;i+=1){
const point=project(i,0,0),backPoint=project(i,0,zSpan);
grid.push(`<line x1="${point.x}" y1="${point.y}" x2="${backPoint.x}" y2="${backPoint.y}" class="viz-3d-floor-line"></line>`);
labels.push(`<text x="${point.x}" y="${point.y+48}" text-anchor="middle" class="viz-3d-x-label">${escapeHtml(clampLabel(xLabels[i].replace(/ copy$/,""),16))}</text>`);
}
for(let i=0;i<zLabels.length;i+=1){
const point=project(0,0,i),rightPoint=project(xSpan,0,i);
grid.push(`<line x1="${point.x}" y1="${point.y}" x2="${rightPoint.x}" y2="${rightPoint.y}" class="viz-3d-floor-line viz-3d-floor-line-depth"></line>`);
labels.push(`<text x="${point.x-134}" y="${point.y+2}" class="viz-3d-z-label">${escapeHtml(clampLabel(zLabels[i].replace(/ copy$/,""),18))}</text>`);
}
const xEnd=project(xSpan,0,0),yEnd=project(0,maxValue*1.08,0),zEnd=project(0,0,zSpan);
axes.push(`<line x1="${project(0,0,0).x}" y1="${project(0,0,0).y}" x2="${xEnd.x}" y2="${xEnd.y}" class="viz-3d-axis-line"></line>`);
axes.push(`<line x1="${project(0,0,0).x}" y1="${project(0,0,0).y}" x2="${yEnd.x}" y2="${yEnd.y}" class="viz-3d-axis-line"></line>`);
axes.push(`<line x1="${project(0,0,0).x}" y1="${project(0,0,0).y}" x2="${zEnd.x}" y2="${zEnd.y}" class="viz-3d-axis-line"></line>`);
const xTitlePoint=project(xSpan*0.62,0,0);
labels.push(`<text x="${xTitlePoint.x+78}" y="${Math.min(height-44,xTitlePoint.y+64)}" class="viz-3d-axis-title viz-3d-axis-title-x">${escapeHtml(visualizationFieldLabel(xField))}</text>`);
labels.push(`<text x="${yEnd.x-184}" y="${Math.max(98,yEnd.y-116)}" transform="rotate(-90 ${yEnd.x-184} ${Math.max(98,yEnd.y-116)})" class="viz-3d-axis-title viz-3d-axis-title-y">${escapeHtml(visualizationFieldLabel(yField))}</text>`);
const zTitlePoint=project(0,0,zSpan*0.52);
labels.push(`<text x="${Math.max(108,zTitlePoint.x-164)}" y="${zTitlePoint.y+78}" class="viz-3d-axis-title viz-3d-axis-title-z">${escapeHtml(visualizationFieldLabel(zField))}</text>`);
const legend=[`<div class="viz-legend-item"><span class="viz-swatch viz-swatch-gradient"></span><span>Low to high ${escapeHtml(visualizationFieldLabel(yField).toLowerCase())}</span></div>`];
return `<div class="viz-3d-axis-guide"><span>X Axis: ${escapeHtml(visualizationFieldLabel(xField))}</span><span>Y Axis: ${escapeHtml(visualizationFieldLabel(yField))}</span><span>Z Axis: ${escapeHtml(visualizationFieldLabel(zField))}</span></div><div class="viz-3d-scene"><svg class="viz-3d-svg" viewBox="0 0 ${width} ${height}" preserveAspectRatio="xMidYMid meet" role="img" aria-label="3D surface plot with ${escapeHtml(visualizationFieldLabel(xField))}, ${escapeHtml(visualizationFieldLabel(yField))}, and ${escapeHtml(visualizationFieldLabel(zField))} axes">${backdrop}${grid.join("")}${floorPlane}${surfacePolygons.join("")}${surfaceLines.join("")}${axes.join("")}${labels.join("")}</svg></div><div class="viz-legend">${legend.join("")}</div>`;}
function scatterMarkup(points,xField,yField){const maxX=Math.max(...points.map(point=>point.x),1),maxY=Math.max(...points.map(point=>point.y),1);return `<div class="viz-scatter">${points.map(point=>`<div class="viz-scatter-point" title="${escapeHtml(point.label)}: ${point.x}, ${point.y}" style="left:${Math.max((point.x/maxX)*100,4)}%;bottom:${Math.max((point.y/maxY)*100,4)}%;background:${chartColor(Math.max(TYPES.indexOf(point.color),0))}"></div>`).join("")}</div><div class="viz-scatter-labels"><span>X: ${escapeHtml(xField)}</span><span>Y: ${escapeHtml(yField)}</span></div>`;}
function toggleVizBuilderFields(){els.vizZFieldWrap?.classList.add("hidden");}
function routeForState(page,noteId){if(page==="data")return"#data";if(page==="settings")return"#settings";if(page==="transactions"&&noteId)return`#note/${noteId}`;return"#notes";}
function replaceRoute(page,noteId){history.replaceState({page,noteId:noteId||null}, "", routeForState(page,noteId));}
function pushRoute(page,noteId){if(isApplyingHistory)return;const target=routeForState(page,noteId);if(window.location.hash===target)return;history.pushState({page,noteId:noteId||null}, "", target);}
function routeStateFromHash(){if(window.location.hash==="#data")return{page:"data",noteId:null};if(window.location.hash==="#settings")return{page:"settings",noteId:null};const match=window.location.hash.match(/^#note\/(.+)$/);if(match)return{page:"transactions",noteId:decodeURIComponent(match[1])};return{page:"notes",noteId:null};}
function updateAccessToggle(){if(!els.accessToggle)return;const count=state.accessRequests.length;els.accessToggle.textContent=count?`Enter Note (${count})`:"Enter Note";}
function updateShareState(){const note=activeNoteObj();els.shareTitle.textContent=note?`Share ${note.title}`:"Open a note to share it";if(els.shareCode)els.shareCode.textContent=note?noteCode(note):"Select a note to see its code";if(els.shareAccessList){if(!note){els.shareAccessList.innerHTML='<div class="empty-state">Open a note to view its access list.</div>';}else if(note.access_type!=="owner"){els.shareAccessList.innerHTML='<div class="empty-state">Only the note owner can view who has access.</div>';}else{const accessList=Array.isArray(note.access_list)?note.access_list:[];els.shareAccessList.innerHTML=accessList.length?accessList.map(entry=>`<div class="share-access-card"><strong>${escapeHtml(entry.user_id)}</strong><small>${formatAccessType(entry.access_type)}${entry.collaborator_tag?` • ${escapeHtml(entry.collaborator_tag)}`:""}</small><div class="share-access-row"><input type="text" maxlength="40" data-tag-user="${escapeHtml(entry.user_id)}" placeholder="Add team or collaborator tag" value="${escapeHtml(entry.collaborator_tag||"")}"><button class="secondary-btn" type="button" data-save-tag="${escapeHtml(entry.user_id)}">Save Tag</button></div></div>`).join(""):'<div class="empty-state">No shared users yet. Only you can access this note now.</div>';els.shareAccessList.querySelectorAll("[data-save-tag]").forEach(button=>button.addEventListener("click",async()=>{const targetUserId=button.getAttribute("data-save-tag");const input=els.shareAccessList.querySelector(`[data-tag-user="${CSS.escape(targetUserId)}"]`);if(!note||!input)return;try{const res=await api("/api/access/tag",{method:"POST",body:JSON.stringify({noteId:note.id,targetUserId,collaboratorTag:input.value})});status(els.shareStatus,res.message,true);await hydrateWorkspace();}catch(err){status(els.shareStatus,err.message);}}));}}if(els.shareToggle)els.shareToggle.disabled=!note;["copyNoteCode","copyNoteLink","exportNoteCsv"].forEach(key=>{if(els[key])els[key].disabled=!note;});if(!note)els.shareDropdown?.classList.add("hidden");}
function renderDataVisualization(){const list=transactionsForCurrentScope();const byType={income:0,expense:0,savings:0,investment:0};const byCount={income:0,expense:0,savings:0,investment:0};const tagCount={};list.forEach(tx=>{byType[tx.type]=(byType[tx.type]||0)+Number(tx.amount||0);byCount[tx.type]=(byCount[tx.type]||0)+1;(tx.tags||[]).forEach(tag=>{const name=tag.name||tag;tagCount[name]=(tagCount[name]||0)+1;});});const totalAmount=Object.values(byType).reduce((sum,value)=>sum+value,0);const topType=Object.entries(byType).sort((a,b)=>b[1]-a[1])[0]?.[0]||"none";if(els.vizContext)els.vizContext.textContent=state.note?`${activeNoteObj()?.title||"Selected note"}`:"All notes";if(els.vizStatGrid)els.vizStatGrid.innerHTML=`<div class="detail-block"><span>Total Tracked</span><strong>${formatCurrency(totalAmount)}</strong><small>${list.length} entries in this view.</small></div><div class="detail-block"><span>Largest Bucket</span><strong>${topType}</strong><small>${formatCurrency(byType[topType]||0)}</small></div><div class="detail-block"><span>Income vs Expense</span><strong>${formatCurrency((byType.income||0)-(byType.expense||0))}</strong><small>Net visible balance trend.</small></div><div class="detail-block"><span>Savings + Investment</span><strong>${formatCurrency((byType.savings||0)+(byType.investment||0))}</strong><small>Long-term money movement.</small></div>`;const maxAmount=Math.max(...Object.values(byType),1);if(els.vizBars)els.vizBars.innerHTML=TYPES.map(type=>`<div class="viz-bar-row"><div class="surface-header"><strong>${type}</strong><small>${byCount[type]} entries • ${formatCurrency(byType[type]||0)}</small></div><div class="viz-bar-track"><div class="viz-bar-fill" style="width:${Math.max(((byType[type]||0)/maxAmount)*100,4)}%"></div></div></div>`).join("");if(els.vizTags){const topTags=Object.entries(tagCount).sort((a,b)=>b[1]-a[1]).slice(0,8);els.vizTags.innerHTML=topTags.length?topTags.map(([tag,count])=>`<span class="tag-suggestion">${escapeHtml(tag)} • ${count}</span>`).join(""):'<div class="empty-state">No tags to visualize yet.</div>';}const scopedList=visualizationList();const chartType=els.vizChartType?.value||"pie";const xField=els.vizXField?.value||"type";const yField=els.vizYField?.value||"amount";const title={pie:"Pie Chart",histogram:"Histogram",scatter:"Scatterplot"}[chartType]||"Custom Visualization";const context=chartType==="pie"?`Slices: ${visualizationFieldLabel(xField)} • Values: ${visualizationFieldLabel(yField)}`:`X: ${visualizationFieldLabel(xField)} • Y: ${visualizationFieldLabel(yField)}`;toggleVizBuilderFields();const start=els.vizStartDate?.value;const end=els.vizEndDate?.value;const summaryBits=[];if(start)summaryBits.push(`from ${start}`);if(end)summaryBits.push(`to ${end}`);if(els.vizBuilderSummary)els.vizBuilderSummary.textContent=chartType==="pie"?`Showing ${scopedList.length} entries ${summaryBits.join(" ")||"for the full timeline"} grouped into pie slices by ${visualizationFieldLabel(xField).toLowerCase()}.`:`Showing ${scopedList.length} entries ${summaryBits.join(" ")||"for the full timeline"} using ${chartType}.`;if(els.vizCustomTitle)els.vizCustomTitle.textContent=title;if(els.vizCustomContext)els.vizCustomContext.textContent=context;if(els.vizDownload)els.vizDownload.disabled=!scopedList.length;if(!els.vizCustomCanvas)return;if(!scopedList.length){state.vizDownloadData=null;els.vizCustomCanvas.innerHTML='<div class="viz-empty">No transactions match the selected timeline.</div>';return;}if(chartType==="pie"){const data=aggregateVisualizationData(scopedList,xField,yField).slice(0,8);state.vizDownloadData={type:"pie",title,context,xField:visualizationFieldLabel(xField),yField,data};els.vizCustomCanvas.innerHTML=`${pieMarkup(data)}${legendMarkup(data,value=>yField==="count"?String(value):formatCurrency(value))}`;return;}if(chartType==="histogram"){const data=histogramData(scopedList,yField);state.vizDownloadData=data.length?{type:"histogram",title,context,xField:visualizationFieldLabel(xField),yField,data}:null;els.vizCustomCanvas.innerHTML=data.length?histogramMarkup(data):'<div class="viz-empty">Choose a numeric Y value to draw a histogram.</div>';return;}if(chartType==="scatter"){const data=scatterData(scopedList,xField,yField);state.vizDownloadData=data.length?{type:"scatter",title,context,xField:visualizationFieldLabel(xField),yField:visualizationFieldLabel(yField),data}:null;els.vizCustomCanvas.innerHTML=data.length?scatterMarkup(data,xField,yField):'<div class="viz-empty">Choose numeric-friendly X and Y fields for a scatterplot.</div>';return;}state.vizDownloadData=null;els.vizCustomCanvas.innerHTML='<div class="viz-empty">Choose one of the available chart types.</div>';}
function renderSettings(){if(els.settingsUser)els.settingsUser.textContent=state.user||"Guest";if(els.settingsTheme)els.settingsTheme.textContent=(els.theme?.selectedOptions?.[0]?.textContent||"Current theme").trim();if(els.settingsNoteCount)els.settingsNoteCount.textContent=String(state.notes.length);if(els.settingsRequestCount)els.settingsRequestCount.textContent=String(state.accessRequests.length);}
function openStaticPage(page,{pushHistory=false}={}){renderDataVisualization();renderSettings();showPage(page);if(pushHistory)pushRoute(page,state.note);}
function setActiveNote(id,{pushHistory=false,pageOverride}={}){state.note=id;const note=activeNoteObj();els.noteBadge.textContent=note?note.title:"No note selected";els.title.textContent=note?`Adding transactions to ${note.title}.`:"Choose or create a note first.";renderNotes();renderTransactions();updateSummary();setComposerEnabled(Boolean(note));updateShareState();renderDataVisualization();renderSettings();showPage(note?(pageOverride||"transactions"):"notes");if(pushHistory)pushRoute(note?(pageOverride||"transactions"):"notes",note?.id||null);}
function applyRouteFromBrowser(){if(!state.user)return;const route=routeStateFromHash();if(route.page==="data"||route.page==="settings"){openStaticPage(route.page);return;}if(route.page==="transactions"&&route.noteId&&state.notes.some(note=>note.id===route.noteId)){setActiveNote(route.noteId);return;}setActiveNote(null);if(window.location.hash&&window.location.hash!=="#notes")replaceRoute("notes",null);}
function filteredNotes(){if(!state.noteSearch.trim())return state.notes;const query=state.noteSearch.trim().toLowerCase();const exact=state.notes.filter(note=>`${note.title} ${note.description||""} ${note.user_id||""}`.toLowerCase().includes(query));if(exact.length)return exact;return state.notes.map(note=>({note,score:fuzzyScore(query,`${note.title} ${note.description||""} ${note.user_id||""}`)})).filter(entry=>entry.score>0).sort((a,b)=>b.score-a.score).map(entry=>entry.note);}
function renderNotes(){els.noteList.innerHTML="";const notes=filteredNotes();if(!state.notes.length){els.noteList.innerHTML='<div class="empty-state">No notes yet. Create one or request access with a note code.</div>';return;}if(!notes.length){els.noteList.innerHTML='<div class="empty-state">No note matched. Fuzzy search also found nothing close.</div>';return;}notes.forEach(note=>{const access=note.access_type==="owner"?"Owner":(note.access_type==="edit"?"Shared edit":"Shared view");const b=document.createElement("button");b.type="button";b.className=`note-card${note.id===state.note?" is-active":""}`;b.innerHTML=`<strong>${note.title}</strong><small>${note.description||"No description"}</small><small>${access}${note.user_id&&note.user_id!==state.user?` by ${note.user_id}`:""}</small><span>${note.transactionCount||0} transaction${note.transactionCount===1?"":"s"}</span>`;b.addEventListener("click",()=>setActiveNote(note.id,{pushHistory:true}));els.noteList.append(b);});}
function renderAccessRequests(){if(!els.accessRequestList)return;els.accessRequestList.innerHTML="";if(!state.accessRequests.length){els.accessRequestList.innerHTML='<div class="empty-state">No pending note approvals.</div>';return;}state.accessRequests.forEach(req=>{const card=document.createElement("div");card.className="access-request-card";card.innerHTML=`<div><strong>${req.requester_user_id}</strong><small>${req.note_title} • ${req.access_type} access</small></div><div class="access-request-actions"><button class="secondary-btn" type="button" data-decision="approve">Approve</button><button class="secondary-btn" type="button" data-decision="reject">Reject</button></div>`;card.querySelectorAll("button").forEach(button=>button.addEventListener("click",async()=>{try{const res=await api("/api/access/approve",{method:"POST",body:JSON.stringify({requestId:req.id,decision:button.dataset.decision})});status(els.accessStatus,res.message,true);await hydrateWorkspace();}catch(err){status(els.accessStatus,err.message);}}));els.accessRequestList.append(card);});}
async function refreshAccessRequests({silent=false}={}){if(!state.user)return;try{const res=await api("/api/access/requests");state.accessRequests=res.requests||[];renderAccessRequests();updateAccessToggle();}catch(err){if(!silent)status(els.accessStatus,err.message);}}
function startSync(){if(syncTimer)clearInterval(syncTimer);syncTimer=setInterval(()=>{if(state.user)hydrateWorkspace();},5000);}
function stopSync(){if(syncTimer){clearInterval(syncTimer);syncTimer=null;}}
function renderPickedTags(){els.tagList.innerHTML="";state.pickedTags.forEach(tag=>{const chip=document.createElement("span");chip.className="tag-chip";chip.innerHTML=`<span>${tag}</span><button type="button">&times;</button>`;chip.querySelector("button").addEventListener("click",()=>{state.pickedTags=state.pickedTags.filter(t=>t!==tag);renderPickedTags();renderTagSuggestions();});els.tagList.append(chip);});}
function renderTagSuggestions(){els.tagSuggestions.innerHTML="";state.tags.filter(t=>!state.pickedTags.includes(t)).slice(0,10).forEach(tag=>{const b=document.createElement("button");b.type="button";b.className="tag-suggestion";b.textContent=tag;b.addEventListener("click",()=>addTag(tag));els.tagSuggestions.append(b);});}
function addTag(tag){const n=normalizeTag(tag);if(!n||state.pickedTags.includes(n))return;state.pickedTags.push(n);els.tagInput.value="";renderPickedTags();renderTagSuggestions();}
function renderAttachmentPreview(){els.attachmentPreview.innerHTML="";state.files.forEach(file=>{const d=document.createElement("div");d.className="attachment-item";d.innerHTML=`<strong>${file.name}</strong><small>${file.type||"application/octet-stream"} • ${formatBytes(file.size)}</small>`;els.attachmentPreview.append(d);});}
function toggleInterest(){const show=["savings","investment"].includes(els.txType.value);els.interestPanel.classList.toggle("hidden",!show);if(!show){els.interestRate.value="";els.interestType.value="none";els.customFormula.value="";els.customFormulaField.classList.add("hidden");els.interestPreview.textContent="Interest is disabled for income and expense entries.";return;}els.customFormulaField.classList.toggle("hidden",els.interestType.value!=="custom");els.interestPreview.textContent=els.interestType.value==="simple"?"Simple interest uses a 1-year projection: principal x rate.":els.interestType.value==="compound"?"Compound interest uses a 1-year projection with annual compounding.":els.interestType.value==="custom"?"Add a custom formula note or leave calculation empty.":"No interest calculation will be stored for this entry.";}
function resetComposer(){els.txForm.reset();state.pickedTags=[];state.files=[];renderPickedTags();renderTagSuggestions();renderAttachmentPreview();setDefaultTxDate();toggleInterest();}

function filteredTransactions(){if(!state.note)return[];let list=state.transactions.filter(t=>t.note_id===state.note);if(state.txFilterType)list=list.filter(t=>t.type===state.txFilterType);if(state.txFilterTag.trim())list=list.filter(t=>(t.tags||[]).some(tag=>String(tag.name||tag).toLowerCase().includes(state.txFilterTag.trim().toLowerCase())));if(state.txFilterDate)list=list.filter(t=>new Date(t.occurredAt).toISOString().slice(0,10)===state.txFilterDate);if(state.txFilterHour)list=list.filter(t=>String(new Date(t.occurredAt).getHours()).padStart(2,"0")===state.txFilterHour);if(state.txSearch.trim()){const query=state.txSearch.trim().toLowerCase();const exact=list.filter(t=>`${t.type} ${t.notes||""} ${t.note?.title||""} ${(t.tags||[]).map(tag=>tag.name||tag).join(" ")}`.toLowerCase().includes(query));list=exact.length?exact:list.map(t=>({t,score:fuzzyScore(query,`${t.type} ${t.notes||""} ${t.note?.title||""} ${(t.tags||[]).map(tag=>tag.name||tag).join(" ")}`)})).filter(entry=>entry.score>0).sort((a,b)=>b.score-a.score).map(entry=>entry.t);}if(state.txSort==="oldest")list=list.sort((a,b)=>new Date(a.occurredAt)-new Date(b.occurredAt));else if(state.txSort==="amount-high")list=list.sort((a,b)=>b.amount-a.amount);else if(state.txSort==="amount-low")list=list.sort((a,b)=>a.amount-b.amount);else list=list.sort((a,b)=>new Date(b.occurredAt)-new Date(a.occurredAt));return list;}
function renderTransactions(){els.txList.innerHTML="";if(!state.notes.length){els.txList.innerHTML='<div class="empty-state">No transactions will appear until you create your first note.</div>';return;}if(!state.note){els.txList.innerHTML='<div class="empty-state">Open one of your notes to see its transactions here.</div>';return;}const list=filteredTransactions();if(!list.length){els.txList.innerHTML='<div class="empty-state">No transactions matched these search words or filters.</div>';return;}list.forEach(tx=>{const aCount=tx.attachments?.length||0;const tags=(tx.tags||[]).map(t=>`<span class="tag-suggestion">${t.name||t}</span>`).join("")||'<span class="tag-suggestion">untagged</span>';const item=document.createElement("article");item.className="transaction-item";item.tabIndex=0;item.innerHTML=`<div class="transaction-item-top"><div><strong>${tx.type}</strong><small>${formatDateTime(tx.occurredAt)}</small></div><div class="transaction-amount">${formatCurrency(tx.amount)}</div></div><p class="transaction-notes">${tx.notes||"No notes added."}</p><div class="transaction-meta"><div class="transaction-inline-tags">${tags}</div><small>${aCount} attachment${aCount===1?"":"s"}</small></div>`;const open=()=>openTx(tx);item.addEventListener("click",open);item.addEventListener("keydown",e=>{if(e.key==="Enter"||e.key===" "){e.preventDefault();open();}});els.txList.append(item);});}
function openTx(tx){const tags=(tx.tags||[]).map(t=>`<span class="tag-suggestion">${t.name||t}</span>`).join("")||'<span class="tag-suggestion">untagged</span>';const attachments=(tx.attachments||[]).map(att=>{const url=attachmentUrl(att),open=`<a class="attachment-link" href="${url}" target="_blank" rel="noopener noreferrer">Open attachment</a>`;if((att.mimeType||"").toLowerCase().startsWith("image/"))return`<div class="attachment-item"><strong>${att.name}</strong><small>${att.mimeType} • ${formatBytes(att.size)}</small><img class="attachment-preview-image" src="${url}" alt="${att.name}">${open}</div>`;if((att.mimeType||"").toLowerCase()==="application/pdf")return`<div class="attachment-item"><strong>${att.name}</strong><small>${att.mimeType} • ${formatBytes(att.size)}</small><iframe class="attachment-preview-frame" src="${url}" title="${att.name}"></iframe>${open}</div>`;return`<div class="attachment-item"><strong>${att.name}</strong><small>${att.mimeType} • ${formatBytes(att.size)}</small>${open}</div>`;}).join("")||'<div class="empty-state">No attachments stored for this entry.</div>';const creatorTag=tx.creator?.collaborator_tag?` • ${escapeHtml(tx.creator.collaborator_tag)}`:"";els.modalTitle.textContent=`${tx.type} details`;els.modalContent.innerHTML=`<div class="detail-grid"><div class="detail-block"><span>Note</span><strong>${tx.note?.title||"Unassigned"}</strong><small>${tx.note?.description||"No note description."}</small></div><div class="detail-block"><span>Amount</span><strong>${formatCurrency(tx.amount)}</strong><small>${tx.currency||"INR"}</small></div><div class="detail-block"><span>Date & Time</span><strong>${formatDateTime(tx.occurredAt)}</strong><small>Saved ${formatDateTime(tx.createdAt||tx.occurredAt)}</small></div><div class="detail-block"><span>Created By</span><strong>${escapeHtml(tx.user_id||"Unknown user")}</strong><small>${tx.note?.user_id===tx.user_id?"Note owner":"Shared collaborator"}${creatorTag}</small></div><div class="detail-block"><span>Projected Return</span><strong>${tx.calculated?.expectedReturn!=null?formatCurrency(tx.calculated.expectedReturn):"N/A"}</strong><small>Final amount: ${tx.calculated?.finalAmount!=null?formatCurrency(tx.calculated.finalAmount):"N/A"}</small></div></div><div class="detail-block"><span>Notes</span><p class="detail-notes">${tx.notes||"No notes added."}</p></div><div class="detail-block"><span>Tags</span><div class="transaction-inline-tags">${tags}</div></div><div class="detail-block"><span>Attachments</span><div class="attachment-preview-list">${attachments}</div></div>`;els.modal.showModal();}
function updateSummary(){const list=state.note?state.transactions.filter(t=>t.note_id===state.note):[];els.sumTotal.textContent=String(list.length);els.sumLast.textContent=list[0]?formatDateTime(list[0].createdAt||list[0].occurredAt):"None";els.sumHelper.textContent=!state.notes.length?"Create your first note to unlock transactions.":!state.note?"Open one of your notes to view its summary.":"Summary for the currently opened note.";}

async function hydrateWorkspace(){if(!state.user)return;try{const [notesRes,txRes,tagsRes,accessRes]=await Promise.all([api("/api/notes"),api("/api/transactions"),api("/api/tags"),api("/api/access/requests")]);state.notes=notesRes.notes||[];state.transactions=txRes.transactions||[];state.tags=tagsRes.tags||[];state.accessRequests=accessRes.requests||[];renderNotes();renderTagSuggestions();renderAccessRequests();updateAccessToggle();renderDataVisualization();renderSettings();const route=routeStateFromHash();const fallbackNoteId=state.notes.some(note=>note.id===state.note)?state.note:null;if(route.page==="transactions"&&route.noteId&&state.notes.some(note=>note.id===route.noteId)){setActiveNote(route.noteId);return;}if(route.page==="data"||route.page==="settings"){state.note=fallbackNoteId;updateShareState();updateSummary();renderTransactions();setComposerEnabled(Boolean(activeNoteObj()));openStaticPage(route.page);replaceRoute(route.page,state.note);return;}setActiveNote(fallbackNoteId);replaceRoute(fallbackNoteId?"transactions":"notes",fallbackNoteId);}catch(err){status(els.txStatus,`Backend unavailable: ${err.message}`);}}

function txPayload(formData){clearErrors(els.txForm);let valid=true;const type=formData.get("type"),amount=Number(formData.get("amount")),occurredAt=dateValue(formData.get("occurredDay"),formData.get("occurredMonth"),formData.get("occurredYear"),formData.get("occurredHour"),formData.get("occurredMinute")),interestType=formData.get("interestType")||"none",rateVal=formData.get("interestRate"),interestRate=rateVal?Number(rateVal):null,customFormula=formData.get("customFormula").trim();if(!state.note){status(els.txStatus,"Select a note before creating a transaction.");valid=false;}if(!TYPES.includes(type)){setError("transaction-type","Choose a valid transaction type.");valid=false;}if(!Number.isFinite(amount)||amount<=0){setError("transaction-amount","Enter a valid INR amount greater than 0.");valid=false;}if(!occurredAt){setError("transaction-datetime","Choose a valid themed date and time.");valid=false;}if(state.files.some(f=>f.size>8*1024*1024)){setError("transaction-attachments","Each file must be 8 MB or smaller.");valid=false;}const needsInterest=["savings","investment"].includes(type);if(needsInterest&&!INTEREST_TYPES.includes(interestType)){setError("interest-type","Choose a valid interest type.");valid=false;}if(needsInterest&&(interestType==="simple"||interestType==="compound")&&(!Number.isFinite(interestRate)||interestRate<0)){setError("interest-rate","Enter a valid interest rate.");valid=false;}return{valid,payload:{noteId:state.note,type,amount,currency:"INR",occurredAt,notes:formData.get("notes").trim(),tags:[...state.pickedTags],interestRate:needsInterest&&Number.isFinite(interestRate)?interestRate:null,interestType:needsInterest?interestType:"none",customFormula:needsInterest&&interestType==="custom"?customFormula:""}};}
function fileToBase64(file){return new Promise((res,rej)=>{const r=new FileReader();r.onload=()=>res(String(r.result).split(",")[1]||"");r.onerror=()=>rej(new Error(`Failed to read ${file.name}.`));r.readAsDataURL(file);});}
async function attachmentPayload(){return Promise.all(state.files.map(async f=>({name:f.name,mimeType:f.type||"application/octet-stream",size:f.size,contentBase64:await fileToBase64(f)})));}

els.tabs.forEach(tab=>tab.addEventListener("click",()=>{status(els.loginStatus,"");status(els.registerStatus,"");clearErrors(els.loginForm);clearErrors(els.registerForm);els.tabs.forEach(t=>{const active=t===tab;t.classList.toggle("is-active",active);t.setAttribute("aria-selected",String(active));});$("#login-panel").classList.toggle("is-active",tab.dataset.tab==="login");$("#register-panel").classList.toggle("is-active",tab.dataset.tab==="register");}));
els.loginForm.addEventListener("submit",e=>{e.preventDefault();clearErrors(els.loginForm);status(els.loginStatus,"");const fd=new FormData(els.loginForm),userId=fd.get("userId").trim(),password=fd.get("password");let valid=true;valid=validateUserId(userId,"login-userid")&&valid;valid=validatePassword(password,"login-password")&&valid;if(!valid){status(els.loginStatus,"Please fix the login errors and try again.");return;}const user=loadUsers().find(u=>u.userId===userId);if(!user){setError("login-userid","User ID does not exist.");status(els.loginStatus,"No account found for this user ID.");return;}if(user.password!==password){setError("login-password","Incorrect password.");status(els.loginStatus,"Login failed. Check your password.");return;}state.user=userId;localStorage.setItem(STORAGE_KEYS.session,userId);els.auth.classList.add("hidden");els.dash.classList.remove("hidden");els.userBadge.textContent=userId;resetComposer();replaceRoute("notes",null);hydrateWorkspace();startSync();});
els.registerForm.addEventListener("submit",e=>{e.preventDefault();clearErrors(els.registerForm);status(els.registerStatus,"");const fd=new FormData(els.registerForm),userId=fd.get("userId").trim(),password=fd.get("password"),confirm=fd.get("confirmPassword"),dob=dateValue(fd.get("dobDay"),fd.get("dobMonth"),fd.get("dobYear")),email=fd.get("email").trim(),phone=fd.get("phone").trim();let valid=true;valid=validateUserId(userId,"register-userid")&&valid;valid=validatePassword(password,"register-password")&&valid;if(confirm!==password){setError("register-confirm-password","This mismaches with the password.");valid=false;}if(!dob){setError("register-dob","Choose a valid date of birth.");valid=false;}if(!emailPattern.test(email)){setError("register-email","Enter a valid email address.");valid=false;}if(!phonePattern.test(phone)){setError("register-phone","Enter phone number with country code, for example +91 9876543210.");valid=false;}if(!valid){status(els.registerStatus,"Please fix the highlighted fields.");return;}const users=loadUsers();if(users.some(u=>u.userId===userId)){setError("register-userid","This user already exists.");status(els.registerStatus,"Choose another user ID.");return;}users.push({userId,password,dob:dob.slice(0,10),email,phone});saveUsers(users);els.registerForm.reset();status(els.registerStatus,"User created successfully. You can login now.",true);$("#login-tab").click();$("#login-userid").value=userId;});
els.noteForm.addEventListener("submit",async e=>{e.preventDefault();clearErrors(els.noteForm);status(els.noteStatus,"");const fd=new FormData(els.noteForm),title=fd.get("title").trim(),description=fd.get("description").trim();if(!title){setError("note-title","Note title is required.");status(els.noteStatus,"Create a note title first.");return;}try{const res=await api("/api/notes",{method:"POST",body:JSON.stringify({title,description})});state.notes=[res.note,...state.notes];els.noteForm.reset();renderNotes();setActiveNote(res.note.id,{pushHistory:true});status(els.noteStatus,"Note created and opened.",true);}catch(err){status(els.noteStatus,err.message);}});
els.txType.addEventListener("change",toggleInterest);els.interestType.addEventListener("change",toggleInterest);
els.addTag.addEventListener("click",()=>addTag(els.tagInput.value));els.tagInput.addEventListener("keydown",e=>{if(e.key==="Enter"||e.key===","){e.preventDefault();addTag(els.tagInput.value);}});
els.attachmentInput.addEventListener("change",()=>{state.files=[...els.attachmentInput.files||[]];renderAttachmentPreview();});
$("#note-search")?.addEventListener("input",e=>{state.noteSearch=e.target.value;renderNotes();});
$("#transaction-search")?.addEventListener("input",e=>{state.txSearch=e.target.value;renderTransactions();});
$("#filter-type")?.addEventListener("change",e=>{state.txFilterType=e.target.value;renderTransactions();});
$("#filter-tag")?.addEventListener("input",e=>{state.txFilterTag=e.target.value;renderTransactions();});
$("#filter-date")?.addEventListener("change",e=>{state.txFilterDate=e.target.value;renderTransactions();});
$("#filter-hour")?.addEventListener("change",e=>{state.txFilterHour=e.target.value;renderTransactions();});
$("#transaction-sort")?.addEventListener("change",e=>{state.txSort=e.target.value;renderTransactions();});
els.txForm.addEventListener("submit",async e=>{e.preventDefault();status(els.txStatus,"");const {valid,payload}=txPayload(new FormData(els.txForm));if(!valid){if(!els.txStatus.textContent)status(els.txStatus,"Please fix the transaction fields and try again.");return;}try{const attachments=await attachmentPayload();const res=await api("/transactions",{method:"POST",body:JSON.stringify({...payload,attachments})});state.transactions=[res.transaction,...state.transactions];state.tags=Array.from(new Set([...state.tags,...(res.transaction.tags||[]).map(t=>t.name||t)])).sort();state.notes=state.notes.map(n=>n.id===res.transaction.note_id?{...n,transactionCount:(n.transactionCount||0)+1}:n);renderNotes();renderTransactions();renderTagSuggestions();updateSummary();resetComposer();status(els.txStatus,"Transaction saved successfully.",true);}catch(err){status(els.txStatus,err.message);}});
els.logout.addEventListener("click",()=>{stopSync();localStorage.removeItem(STORAGE_KEYS.session);state.user=null;state.note=null;state.currentPage="notes";state.notes=[];state.transactions=[];state.tags=[];state.pickedTags=[];state.files=[];state.accessRequests=[];els.dash.classList.add("hidden");els.auth.classList.remove("hidden");els.loginForm.reset();els.registerForm.reset();els.noteForm.reset();resetComposer();renderNotes();renderAccessRequests();renderDataVisualization();renderSettings();updateAccessToggle();setActiveNote(null);history.replaceState({}, "", window.location.pathname+window.location.search);status(els.loginStatus,"");status(els.registerStatus,"");status(els.noteStatus,"");status(els.txStatus,"");status(els.accessStatus,"");});
els.backToNotes?.addEventListener("click",()=>setActiveNote(null,{pushHistory:true}));
els.toggleFilters?.addEventListener("click",()=>setFilterPanel(els.filterPanel.classList.contains("hidden")));
els.shareToggle?.addEventListener("click",()=>{if(els.shareToggle.disabled)return;els.shareDropdown?.classList.toggle("hidden");});
els.accessToggle?.addEventListener("click",async()=>{els.accessDropdown?.classList.toggle("hidden");if(!els.accessDropdown?.classList.contains("hidden"))await refreshAccessRequests({silent:true});});
els.toolbarToggle?.addEventListener("click",()=>els.toolbarDropdown?.classList.toggle("hidden"));
els.toolbarWorkspace?.addEventListener("click",()=>{els.toolbarDropdown?.classList.add("hidden");if(state.note)setActiveNote(state.note,{pushHistory:true});else setActiveNote(null,{pushHistory:true});});
els.toolbarData?.addEventListener("click",()=>{els.toolbarDropdown?.classList.add("hidden");openStaticPage("data",{pushHistory:true});});
els.toolbarSettings?.addEventListener("click",()=>{els.toolbarDropdown?.classList.add("hidden");openStaticPage("settings",{pushHistory:true});});
els.accessForm?.addEventListener("submit",async e=>{e.preventDefault();status(els.accessStatus,"");const fd=new FormData(els.accessForm),code=String(fd.get("code")||"").trim(),accessType=String(fd.get("accessType")||"view");if(!code){status(els.accessStatus,"Paste a note code first.");return;}try{const res=await api("/api/access/request",{method:"POST",body:JSON.stringify({code,accessType})});els.accessForm.reset();status(els.accessStatus,res.message,true);await hydrateWorkspace();}catch(err){status(els.accessStatus,err.message);}});
["change","input"].forEach(eventName=>{els.vizChartType?.addEventListener(eventName,renderDataVisualization);els.vizXField?.addEventListener(eventName,renderDataVisualization);els.vizYField?.addEventListener(eventName,renderDataVisualization);els.vizZField?.addEventListener(eventName,renderDataVisualization);els.vizStartDate?.addEventListener(eventName,renderDataVisualization);els.vizEndDate?.addEventListener(eventName,renderDataVisualization);});
els.vizResetRange?.addEventListener("click",()=>{if(els.vizStartDate)els.vizStartDate.value="";if(els.vizEndDate)els.vizEndDate.value="";renderDataVisualization();});
els.vizDownload?.addEventListener("click",downloadVisualization);
els.copyNoteCode?.addEventListener("click",async()=>{const note=activeNoteObj();if(!note)return;await navigator.clipboard.writeText(noteCode(note));status(els.shareStatus,"Note code copied.",true);});
els.copyNoteLink?.addEventListener("click",async()=>{const note=activeNoteObj();if(!note)return;const url=`${window.location.origin}${window.location.pathname}#note=${note.id}`;await navigator.clipboard.writeText(url);status(els.shareStatus,"Note link copied.",true);});
els.exportNoteCsv?.addEventListener("click",()=>{const note=activeNoteObj();if(!note)return;const rows=state.transactions.filter(tx=>tx.note_id===note.id);const csv=["type,amount,currency,occurredAt,notes,tags"];rows.forEach(tx=>csv.push([tx.type,tx.amount,tx.currency||"INR",tx.occurredAt,`"${String(tx.notes||"").replace(/"/g,'""')}"`,`"${(tx.tags||[]).map(t=>t.name||t).join(" | ")}"`].join(",")));const blob=new Blob([csv.join("\n")],{type:"text/csv;charset=utf-8"});const a=document.createElement("a");a.href=URL.createObjectURL(blob);a.download=`${(note.title||"note").replace(/\s+/g,"-").toLowerCase()}.csv`;document.body.append(a);a.click();a.remove();URL.revokeObjectURL(a.href);status(els.shareStatus,"CSV exported.",true);});
document.addEventListener("click",e=>{if(!els.shareMenu?.contains?.(e.target)&&els.shareDropdown&&!els.shareDropdown.classList.contains("hidden"))els.shareDropdown.classList.add("hidden");if(!els.accessMenu?.contains?.(e.target)&&els.accessDropdown&&!els.accessDropdown.classList.contains("hidden"))els.accessDropdown.classList.add("hidden");if(!els.toolbarMenu?.contains?.(e.target)&&els.toolbarDropdown&&!els.toolbarDropdown.classList.contains("hidden"))els.toolbarDropdown.classList.add("hidden");});
window.addEventListener("popstate",()=>{if(!state.user)return;isApplyingHistory=true;applyRouteFromBrowser();isApplyingHistory=false;});
